query:
SELECT COUNT(*) as totalUsers FROM users;
SELECT COUNT(DISTINCT ts.userId) as usersWithSets FROM training_sets ts WHERE ts.userId IS NOT NULL;
SELECT COUNT(DISTINCT ts.deviceId) as guestsWithSets FROM training_sets ts WHERE ts.deviceId IS NOT NULL AND ts.userId IS NULL;
SELECT COUNT(DISTINCT ch.userId) as usersWithCycles FROM cycle_history ch WHERE ch.userId IS NOT NULL AND ch.userId > 0;
SELECT COUNT(DISTINCT ch.deviceId) as guestsWithCycles FROM cycle_history ch WHERE ch.deviceId IS NOT NULL AND (ch.userId IS NULL OR ch.userId = 0);

